DROP TABLE IF EXISTS `import_job`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!50503 SET character_set_client = utf8mb4 */;
CREATE TABLE `import_job` (
  `id` bigint NOT NULL AUTO_INCREMENT,
  `module` varchar(20) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `source_file_name` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `status` varchar(30) CHARACTER SET utf8mb4 COLLATE utf8mb4_unicode_ci NOT NULL,
  `total_rows` int unsigned NOT NULL,
  `valid_rows` int unsigned NOT NULL,
  `invalid_rows` int unsigned NOT NULL,
  `saved_rows` int unsigned NOT NULL,
  `started_at` datetime(6) DEFAULT NULL,
  `completed_at` datetime(6) DEFAULT NULL,
  `created_at` datetime(6) NOT NULL,
  `updated_at` datetime(6) NOT NULL,
  `initiated_by_id` int DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `import_job_module_a69cf9_idx` (`module`),
  KEY `import_job_status_7cd937_idx` (`status`),
  KEY `import_job_created_d7bb74_idx` (`created_at`),
  KEY `imports_importjob_initiated_by_id_e282e52c_fk_auth_user_id` (`initiated_by_id`),
  CONSTRAINT `imports_importjob_initiated_by_id_e282e52c_fk_auth_user_id` FOREIGN KEY (`initiated_by_id`) REFERENCES `user` (`id`),
  CONSTRAINT `import_job_chk_1` CHECK ((`total_rows` >= 0)),
  CONSTRAINT `import_job_chk_2` CHECK ((`valid_rows` >= 0)),
  CONSTRAINT `import_job_chk_3` CHECK ((`invalid_rows` >= 0)),
  CONSTRAINT `import_job_chk_4` CHECK ((`saved_rows` >= 0)),
  CONSTRAINT `import_job_invalid_rows_lte_total_rows` CHECK ((`invalid_rows` <= `total_rows`)),
  CONSTRAINT `import_job_invalid_rows_non_negative` CHECK ((`invalid_rows` >= 0)),
  CONSTRAINT `import_job_saved_rows_lte_valid_rows` CHECK ((`saved_rows` <= `valid_rows`)),
  CONSTRAINT `import_job_saved_rows_non_negative` CHECK ((`saved_rows` >= 0)),
  CONSTRAINT `import_job_total_rows_non_negative` CHECK ((`total_rows` >= 0)),
  CONSTRAINT `import_job_valid_rows_lte_total_rows` CHECK ((`valid_rows` <= `total_rows`)),
  CONSTRAINT `import_job_valid_rows_non_negative` CHECK ((`valid_rows` >= 0))
) ENGINE=InnoDB AUTO_INCREMENT=22 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_unicode_ci;
